mapper.select:
select count(*) as totalCount, coalesce(sum(case when review_status = 'reviewing' then 1 else 0 end), 0) as reviewingCount, coalesce(sum(case when review_status = 'pending' then 1 else 0 end), 0) as pendingCount, coalesce(sum(case when review_status = 'returned' then 1 else 0 end), 0) as returnedCount, coalesce(sum(case when review_status = 'approved' then 1 else 0 end), 0) as approvedCount, coalesce(sum(case when task_status = 'archived' then 1 else 0 end), 0) as archivedCount, coalesce(sum(case when submit_time >= curdate() and submit_time < date_add(curdate(), interval 1 day) then 1 else 0 end), 0) as todayNewCount, coalesce(sum(case when review_status in ('reviewing', 'pending', 'returned') or process_flag = '1' or task_status = 'paused' then 1 else 0 end), 0) as todoCount, coalesce(sum(case when process_flag = '1' or task_status = 'paused' then 1 else 0 end), 0) as pausedCount, coalesce(sum(case when priority = 'high' and review_status in ('reviewing', 'pending', 'returned') then 1 else 0 end), 0) as highPriorityPendingCount from audit_review_task
del_flag = '0'
and create_by = #{createBy}

mapper.update:
update audit_review_task
task_no = #{taskNo}, product_name = #{productName}, delivery_unit = #{deliveryUnit}, sponsor = #{sponsor}, handler_name = #{handlerName}, priority = #{priority}, ai_analysis_count = #{aiAnalysisCount}, task_status = #{taskStatus}, review_status = #{reviewStatus}, process_flag = #{processFlag}, current_version_no = #{currentVersionNo}, main_report_urls = #{mainReportUrls}, basis_file_urls = #{basisFileUrls}, appendix_file_urls = #{appendixFileUrls}, submit_time = #{submitTime}, remark = #{remark}, update_by = #{updateBy}, update_time = sysdate()
where task_id = #{taskId}

update audit_review_version
set current_flag = '0'
where task_id = #{taskId}

